try:
    # 1. Fetch SAF location IDs to check duplicates
    req = urllib.request.Request(f"{url}/rest/v1/leads?select=cqc_location_id&campaign_type=eq.5_week_saf_campaign", headers={'apikey': key, 'Authorization': f'Bearer {key}'})
    with urllib.request.urlopen(req) as resp:
        saf_leads = json.loads(resp.read().decode())
    saf_location_ids = {l['cqc_location_id'] for l in saf_leads if l['cqc_location_id']}

    # 2. Parse TSV
    f = io.StringIO(tsv_data)
    reader = csv.DictReader(f, delimiter='\t')
    
    duplicates = 0
    patched = 0
    rejected = 0
    now_iso = datetime.utcnow().isoformat() + "Z"
    
    for row in reader:
        lead_id = row['id']
        location_id = row.get('cqc_location_id')
        
        # Check duplicate
        if location_id in saf_location_ids:
            duplicates += 1
            print(f"Skipping duplicate: {row.get('name')}")
            continue
            
        # Parse out best email and best name from TSV
        # Possible email columns: director_email, nominated_individual_email, email
        best_email = row.get('director_email') or row.get('nominated_individual_email') or row.get('email') or ""
        # Best name: director_name, registered_manager, nominated_individual
        best_name = row.get('director_name') or row.get('registered_manager') or row.get('nominated_individual') or ""
        
        if "pending" in best_email or not best_email or "@" not in best_email or "undefined" in best_email:
            rejected += 1
            print(f"Rejected (No usable email): {row.get('name')} | {best_email}")
            continue
            
        # Ensure best_name is clean. Sometimes people write 'undefined undefined'.
        if "undefined" in best_name:
            best_name = ""
            
        patch_payload = {
            "campaign_type": "5_week_saf_campaign",
            "current_phase": 0,          # Set phase to 0 so they get Week 1!
            "next_step_date": now_iso,   # Set next step date to right now to dispatch today!
            "status": "active",
            "email_enrichment_status": "found",
            "name": best_name.strip(),
            "email": best_email.strip()
        }
        
        patch_req = urllib.request.Request(
            f"{url}/rest/v1/leads?id=eq.{lead_id}", 
            data=json.dumps(patch_payload).encode(), 
            headers=headers, 
            method='PATCH'
        )
        urllib.request.urlopen(patch_req)
        patched += 1
        print(f"Successfully migrated and queued: {best_name} ({best_email}) -> SAF Phase 1")

    print(f"\nFinal Statistics:")
    print(f"Duplicates skipped: {duplicates}")
    print(f"Rejected (no usable email): {rejected}")
    print(f"Successfully migrated and queued: {patched}")
    
except Exception as e:
    print(str(e))
